hbs.a_button:
{{#if href}}<a
 href="{{href}}"{{else}}<span{{/if}}
 class="a_button {{style}}">
{{> a_icon icon=icon_before }}
<span>{{text}}</span>
{{> a_icon icon=icon_after }}
{{#if href}}</a>{{else}}</span>{{/if}}

hbs.a_icon:
{{#with a_icon}}
{{> a_icon }}
{{else}}
{{#if icon}}
<span class="a_icon"
 data-icon="{{icon}}"
 style="--icon: {{lucideSvgUrl icon fill stroke stroke_width}}"
 aria-hidden="true"></span>
{{/if}}
{{/with}}

hbs.a_image:
{{#if a_image.src}}
<{{#if a_image.href}}a href="{{a_image.href}}"{{else}}div{{/if}} class="a_image">
<img
 src="{{a_image.src}}"
 alt="{{a_image.alt}}"
 {{#if a_image.width}} width="{{parseInt a_image.width}}"{{/if}}
 {{#if a_image.height}} height="{{parseInt a_image.height}}"{{/if}}
 {{#if a_image.fetchpriority}} fetchpriority="{{a_image.fetchpriority}}"{{/if}}
 {{#if a_image.loading}} loading="{{a_image.loading}}"{{/if}}
 />
</{{#if a_image.href}}a{{else}}div{{/if}}>
{{/if}}

